import { useEffect, useState } from 'react';
import { supabase } from '../lib/supabase';
import { useAuthStore } from '../lib/store';

export interface CardWithProgram {
  id: string;
  current_stamps: number;
  current_points: number;
  tier: string;
  last_activity: string;
  loyalty_programs: {
    id: string;
    name: string;
    type: 'stamp' | 'points';
    stamp_goal: number | null;
    reward_description: string | null;
    merchants: { name: string; logo_url: string | null };
  };
}

export function useCards() {
  const [cards, setCards] = useState<CardWithProgram[]>([]);
  const [loading, setLoading] = useState(true);
  const session = useAuthStore((s) => s.session);

  async function fetchCards() {
    if (!session) return;
    const { data } = await supabase
      .from('customer_cards')
      .select('*, loyalty_programs(*, merchants(name, logo_url))')
      .eq('customer_id', session.user.id)
      .order('last_activity', { ascending: false });
    setCards((data as any) ?? []);
    setLoading(false);
  }

  useEffect(() => { fetchCards(); }, [session]);

  return { cards, loading, refresh: fetchCards };
}
```

