import { createClient } from 'https://esm.sh/@supabase/supabase-js@2';

const corsHeaders = {
  'Access-Control-Allow-Origin': '*',
  'Access-Control-Allow-Headers': 'authorization, x-client-info, apikey, content-type',
};

Deno.serve(async (req) => {
  if (req.method === 'OPTIONS') return new Response('ok', { headers: corsHeaders });

  try {
    const supabase = createClient(
      Deno.env.get('SUPABASE_URL')!,
      Deno.env.get('SUPABASE_SERVICE_ROLE_KEY')!
    );

    const authHeader = req.headers.get('Authorization');
    if (!authHeader) return new Response(JSON.stringify({ error: 'No auth' }), { status: 401, headers: corsHeaders });

    const { data: { user } } = await supabase.auth.getUser(authHeader.replace('Bearer ', ''));
    if (!user) return new Response(JSON.stringify({ error: 'Unauthorized' }), { status: 401, headers: corsHeaders });

    const { card_id, reward_id } = await req.json();
    if (!card_id || !reward_id) return new Response(JSON.stringify({ error: 'Missing card_id or reward_id' }), { status: 400, headers: corsHeaders });

    const { data: card } = await supabase.from('customer_cards').select('*, loyalty_programs(type)').eq('id', card_id).eq('customer_id', user.id).single();
    if (!card) return new Response(JSON.stringify({ error: 'Card not found' }), { status: 404, headers: corsHeaders });

    const { data: reward } = await supabase.from('rewards').select('*').eq('id', reward_id).eq('is_active', true).single();
    if (!reward) return new Response(JSON.stringify({ error: 'Reward not found' }), { status: 404, headers: corsHeaders });

    const programType = card.loyalty_programs.type;
    if (programType === 'stamp' && card.current_stamps < (reward.stamps_required || 0)) {
      return new Response(JSON.stringify({ error: 'Not enough stamps' }), { status: 400, headers: corsHeaders });
    }
    if (programType === 'points' && card.current_points < (reward.points_cost || 0)) {
      return new Response(JSON.stringify({ error: 'Not enough points' }), { status: 400, headers: corsHeaders });
    }

    if (programType === 'stamp') {
      await supabase.from('customer_cards').update({
        current_stamps: card.current_stamps - (reward.stamps_required || 0),
        last_activity: new Date().toISOString(),
      }).eq('id', card.id);
    } else {
      await supabase.from('customer_cards').update({
        current_points: card.current_points - (reward.points_cost || 0),
        last_activity: new Date().toISOString(),
      }).eq('id', card.id);
    }

    await supabase.from('transactions').insert({
      card_id: card.id,
      type: 'reward_redeem',
      value: reward.stamps_required || reward.points_cost || 0,
      validated_by: 'manual',
    });

    return new Response(JSON.stringify({
      success: true,
      reward_name: reward.name,
      discount_type: reward.discount_type,
      discount_value: reward.discount_value,
    }), { status: 200, headers: { ...corsHeaders, 'Content-Type': 'application/json' } });

  } catch (err) {
    return new Response(JSON.stringify({ error: (err as Error).message }), { status: 500, headers: corsHeaders });
  }
});

import { useEffect, useState } from 'react';
import { View, Text, FlatList, TouchableOpacity, StyleSheet, Alert, RefreshControl } from 'react-native';
import { supabase } from '../../lib/supabase';
import { useAuthStore } from '../../lib/store';

interface RewardItem {
  id: string;
  name: string;
  description: string | null;
  discount_type: string;
  discount_value: number;
  points_cost: number | null;
  stamps_required: number | null;
  program_name: string;
  program_type: string;
  card_id: string;
  can_redeem: boolean;
}

export default function RewardsScreen() {
  const [rewards, setRewards] = useState<RewardItem[]>([]);
  const [loading, setLoading] = useState(true);
  const session = useAuthStore((s) => s.session);

  async function fetchRewards() {
    if (!session) return;
    const { data: cards } = await supabase
      .from('customer_cards')
      .select('*, loyalty_programs(name, type, rewards(*))')
      .eq('customer_id', session.user.id);

    const items: RewardItem[] = [];
    cards?.forEach((card: any) => {
      const program = card.loyalty_programs;
      program.rewards?.forEach((r: any) => {
        const canRedeem = program.type === 'stamp'
          ? card.current_stamps >= (r.stamps_required || 0)
          : card.current_points >= (r.points_cost || 0);
        items.push({
          ...r,
          program_name: program.name,
          program_type: program.type,
          card_id: card.id,
          can_redeem: canRedeem,
        });
      });
    });
    setRewards(items);
    setLoading(false);
  }

  useEffect(() => { fetchRewards(); }, [session]);

  async function handleRedeem(item: RewardItem) {
    Alert.alert('Redeem Reward', `Use ${item.program_type === 'stamp' ? item.stamps_required + ' stamps' : item.points_cost + ' points'} for "${item.name}"?`, [
      { text: 'Cancel' },
      {
        text: 'Redeem', onPress: async () => {
          const { data, error } = await supabase.functions.invoke('redeem-reward', {
            body: { card_id: item.card_id, reward_id: item.id },
          });
          if (error) { Alert.alert('Error', error.message); return; }
          Alert.alert('Redeemed!', `You got: ${data.reward_name}`);
          fetchRewards();
        },
      },
    ]);
  }

  return (
    <View style={styles.container}>
      <Text style={styles.title}>Rewards</Text>
      <FlatList
        data={rewards}
        keyExtractor={(item) => item.id}
        renderItem={({ item }) => (
          <View style={styles.card}>
            <Text style={styles.program}>{item.program_name}</Text>
            <Text style={styles.name}>{item.name}</Text>
            {item.description && <Text style={styles.desc}>{item.description}</Text>}
            <Text style={styles.cost}>
              {item.program_type === 'stamp' ? `${item.stamps_required} stamps` : `${item.points_cost} pts`}
              {' \u00b7 '}
              {item.discount_type === 'freebie' ? 'Free' : `${item.discount_value}${item.discount_type === 'percentage' ? '%' : '\u20ac'} off`}
            </Text>
            <TouchableOpacity
              style={[styles.button, !item.can_redeem && styles.buttonDisabled]}
              onPress={() => handleRedeem(item)}
              disabled={!item.can_redeem}
            >
              <Text style={styles.buttonText}>{item.can_redeem ? 'Redeem' : 'Not enough'}</Text>
            </TouchableOpacity>
          </View>
        )}
        ListEmptyComponent={<Text style={styles.empty}>{loading ? 'Loading...' : 'No rewards available yet.'}</Text>}
        refreshControl={<RefreshControl refreshing={loading} onRefresh={fetchRewards} />}
        contentContainerStyle={styles.list}
      />
    </View>
  );
}

const styles = StyleSheet.create({
  container: { flex: 1, backgroundColor: '#f5f5f5' },
  title: { fontSize: 28, fontWeight: 'bold', padding: 24, paddingBottom: 12 },
  list: { paddingHorizontal: 16 },
  card: { backgroundColor: '#fff', borderRadius: 16, padding: 16, marginBottom: 12, shadowColor: '#000', shadowOpacity: 0.05, shadowRadius: 10, elevation: 2 },
  program: { fontSize: 12, color: '#888', marginBottom: 4 },
  name: { fontSize: 18, fontWeight: '700', marginBottom: 4 },
  desc: { fontSize: 14, color: '#666', marginBottom: 8 },
  cost: { fontSize: 14, color: '#6366f1', fontWeight: '600', marginBottom: 12 },
  button: { backgroundColor: '#6366f1', padding: 12, borderRadius: 10, alignItems: 'center' },
  buttonDisabled: { backgroundColor: '#d1d5db' },
  buttonText: { color: '#fff', fontWeight: '600' },
  empty: { textAlign: 'center', color: '#999', marginTop: 40, fontSize: 16 },
});
